CREATE INDEX idx_obs_created ON observations(created_at);
CREATE TRIGGER observations_ai AFTER INSERT ON observations BEGIN
    INSERT INTO observations_fts(rowid, content) VALUES (new.id, new.content);
END;
CREATE TRIGGER observations_au AFTER UPDATE ON observations BEGIN
    INSERT INTO observations_fts(observations_fts, rowid, content) VALUES('delete', old.id, old.content);
    INSERT INTO observations_fts(rowid, content) VALUES (new.id, new.content);
END;
CREATE TRIGGER observations_ad AFTER DELETE ON observations BEGIN
    INSERT INTO observations_fts(observations_fts, rowid, content) VALUES('delete', old.id, old.content);
END;
CREATE INDEX idx_metrics_event ON metrics(event_type);
CREATE INDEX idx_metrics_created ON metrics(created_at);
CREATE VIEW baked_observations AS
SELECT
    id,
    node_id,
    content,
    tag,
    importance,
    created_at,
    structural_hash
FROM observations
WHERE is_active = 1
  AND is_baked = 1
  AND superseded_at IS NULL;
CREATE INDEX idx_obs_vantage_read ON observations(is_active, is_baked, superseded_at);
CREATE INDEX idx_nodes_uid ON nodes(uid);
CREATE INDEX idx_obs_node ON observations(node_id);
CREATE INDEX idx_obs_commit ON observations(commit_id);
CREATE INDEX idx_obs_branch ON observations(branch);
CREATE INDEX idx_obs_namespace ON observations(namespace);
CREATE INDEX idx_obs_scope_created ON observations(scope, created_at DESC);
CREATE INDEX idx_obs_node_scope ON observations(node_id, scope);
CREATE INDEX idx_obs_symbol ON observations(symbol);
CREATE INDEX idx_obs_active_score ON observations(is_active, materialized_score DESC);
CREATE INDEX idx_obs_hash ON observations(structural_hash);
CREATE INDEX idx_obs_bucket ON observations(created_at_bucket, importance);
CREATE INDEX idx_nodes_type ON nodes(node_type);
CREATE INDEX idx_nodes_status ON nodes(status);
